import{_ as e,o,c,f as t}from"./app-19f36e20.js";const a={},d=t('<h1 id="如何设置-godot-引擎" tabindex="-1"><a class="header-anchor" href="#如何设置-godot-引擎" aria-hidden="true">#</a> 如何设置 Godot 引擎？</h1><h2 id="如何设计游戏显示窗口的大小" tabindex="-1"><a class="header-anchor" href="#如何设计游戏显示窗口的大小" aria-hidden="true">#</a> 如何设计游戏显示窗口的大小？</h2><p>一般来说，我们会将游戏显示窗口的宽高按照 16 ：9 的比例进行设置，从而，满足绝大多数的电脑显示器。常用的尺寸有<code>1920×1080，1280×720</code>。</p><p>拉伸模式设为 <code>canvas_items</code>（表示对象将根据其父级的大小进行拉伸。这意味着对象将始终保持与其父级相同的比例，无论其父级的大小如何 ）。</p><p>拉伸比例设为 <code>keep</code>（画面会被拉伸以填满整个视口，但不会变形。如果视口的宽高比例和游戏画面不同，会出现黑边）。</p><p>总之，只要能让我们的游戏画面更加清晰，怎么着都行。</p>',6),r=[d];function n(s,i){return o(),c("div",null,r)}const _=e(a,[["render",n],["__file","project-config.html.vue"]]);export{_ as default};
